import React, { useEffect, useRef, useState } from 'react';
import {
  Stage,
  Layer,
  Group,
  Image as KonvaImage,
  Rect,
  Line,
  Circle,
  Transformer
} from 'react-konva';
import './AnnotationCanvas.css';

/**
 * This version:
 *  1) Bounding boxes => finalize on mouse up (no Enter needed).
 *  2) Polygons => finalize on double-click.
 *  3) Bounding boxes => Transformer with 8 handles for resizing/moving.
 *  4) Polygons => Circle handles on each vertex to reshape. Entire polygon is draggable.
 *  5) The entire image is draggable if selectedTool === 'move'.
 */
export default function AnnotationCanvas({
  fileUrl,
  annotations,          // array of objects: { type: 'bbox' | 'polygon', ... }
  onAnnotationsChange,  // callback to update annotation array
  selectedTool,         // 'move', 'bbox', or 'polygon'
  scale,
  onWheelZoom,
  activeLabelColor
}) {
  const stageRef = useRef(null);
  const containerRef = useRef(null);

  // For bounding boxes, we track references so we can attach one Transformer
  const rectRefs = useRef([]);
  const transformerRef = useRef(null);

  // Which bounding box is selected? (for Transformer)
  const [selectedShapeIndex, setSelectedShapeIndex] = useState(null);

  const [dims, setDims] = useState({ width: 0, height: 0 });
  const [konvaImg, setKonvaImg] = useState(null);
  // Entire "anno-group" offset => user can pan the image if tool="move"
  const [imagePos, setImagePos] = useState({ x: 0, y: 0 });

  // In-progress bounding box
  const [newBox, setNewBox] = useState(null);

  // In-progress polygon
  const [tempPoints, setTempPoints] = useState([]);
  const [drawingPolygon, setDrawingPolygon] = useState(false);

  // --------------------------------------
  // Resize container
  // --------------------------------------
  useEffect(() => {
    const handleResize = () => {
      if (containerRef.current) {
        setDims({
          width: containerRef.current.offsetWidth,
          height: containerRef.current.offsetHeight
        });
      }
    };
    window.addEventListener('resize', handleResize);
    handleResize();
    return () => window.removeEventListener('resize', handleResize);
  }, []);

  // --------------------------------------
  // Load image
  // --------------------------------------
  useEffect(() => {
    if (!fileUrl) return;
    const img = new Image();
    img.src = fileUrl;
    img.onload = () => {
      setKonvaImg(img);
      setImagePos({ x: 0, y: 0 });
    };
    img.onerror = () => console.error('Could not load image:', fileUrl);
  }, [fileUrl]);

  // --------------------------------------
  // Flatten {x,y} => [x1,y1,x2,y2,...]
  // --------------------------------------
  const flattenPoints = (pts) => pts.flatMap((p) => [p.x, p.y]);

  // --------------------------------------
  // get pointer pos in local coords of "anno-group"
  // --------------------------------------
  const getGroupPos = (evt) => {
    const group = stageRef.current?.findOne('#anno-group');
    return group ? group.getRelativePointerPosition() : null;
  };

  // --------------------------------------
  // BOUNDING BOX (new)
  // --------------------------------------
  const startBox = (pos) => {
    setNewBox({ x: pos.x, y: pos.y, width: 0, height: 0 });
  };
  const updateBox = (pos) => {
    if (!newBox) return;
    setNewBox({
      ...newBox,
      width: pos.x - newBox.x,
      height: pos.y - newBox.y
    });
  };
  // Finalize on mouse up (instead of Enter)
  const finalizeBox = () => {
    if (!newBox) return;
    onAnnotationsChange([...annotations, { type: 'bbox', ...newBox }]);
    setNewBox(null);
  };

  // --------------------------------------
  // POLYGON (new)
  // --------------------------------------
  const addPolygonPoint = (pos) => {
    setTempPoints((prev) => [...prev, pos]);
    setDrawingPolygon(true);
  };
  const removeLastPolygonPoint = () => {
    setTempPoints((prev) => prev.slice(0, -1));
  };
  // finalize polygon on double-click (unchanged)
  const finalizePolygon = () => {
    if (tempPoints.length >= 3) {
      onAnnotationsChange([
        ...annotations,
        { type: 'polygon', points: tempPoints }
      ]);
    }
    setTempPoints([]);
    setDrawingPolygon(false);
  };

  // --------------------------------------
  // MOUSE: create new shapes
  // --------------------------------------
  const handleMouseDown = (evt) => {
    if (selectedTool === 'move') return; // do not create shapes in move mode

    const pos = getGroupPos(evt);
    if (!pos) return;

    // unselect bounding box if we start a new shape
    setSelectedShapeIndex(null);

    if (selectedTool === 'bbox') {
      startBox(pos);
    } else if (selectedTool === 'polygon') {
      addPolygonPoint(pos);
    }
  };

  const handleMouseMove = (evt) => {
    if (selectedTool === 'bbox' && newBox) {
      const pos = getGroupPos(evt);
      if (pos) updateBox(pos);
    }
  };

  // bounding box now finalizes on mouse up
  const handleMouseUp = () => {
    if (selectedTool === 'bbox' && newBox) {
      finalizeBox();
    }
  };

  // polygon finalizes on double-click
  const handleDblClick = () => {
    if (selectedTool === 'polygon' && drawingPolygon) {
      finalizePolygon();
    }
  };

  // --------------------------------------
  // If you still want ESC or Backspace for polygons,
  // you can keep or remove this code.
  // --------------------------------------
  useEffect(() => {
    const onKeyDown = (e) => {
      if (
        e.key === 'Backspace' &&
        selectedTool === 'polygon' &&
        drawingPolygon
      ) {
        e.preventDefault();
        removeLastPolygonPoint();
      }
    };

    const onCancelAnnotation = () => {
      // ESC => cancel in-progress shapes
      setNewBox(null);
      setTempPoints([]);
      setDrawingPolygon(false);
    };

    window.addEventListener('keydown', onKeyDown);
    window.addEventListener('cancel-annotation', onCancelAnnotation);
    return () => {
      window.removeEventListener('keydown', onKeyDown);
      window.removeEventListener('cancel-annotation', onCancelAnnotation);
    };
  }, [selectedTool, drawingPolygon, newBox, tempPoints]);

  // --------------------------------------
  // WHEEL => zoom
  // --------------------------------------
  const handleWheel = (evt) => {
    evt.evt.preventDefault();
    onWheelZoom(evt.evt.deltaY);
  };

  // --------------------------------------
  // BOUNDING BOX => Transformer
  // --------------------------------------
  useEffect(() => {
    if (!transformerRef.current) return;
    const transformer = transformerRef.current;

    if (selectedShapeIndex == null) {
      transformer.nodes([]);
      transformer.getLayer()?.batchDraw();
      return;
    }

    const ann = annotations[selectedShapeIndex];
    if (!ann || ann.type !== 'bbox') {
      transformer.nodes([]);
      transformer.getLayer()?.batchDraw();
      return;
    }

    const rectNode = rectRefs.current[selectedShapeIndex];
    if (rectNode) {
      transformer.nodes([rectNode]);
      transformer.getLayer().batchDraw();
    }
  }, [selectedShapeIndex, annotations]);

  const handleRectDragEnd = (index, e) => {
    const { x, y } = e.target.position();
    const updated = [...annotations];
    updated[index] = { ...updated[index], x, y };
    onAnnotationsChange(updated);
  };

  const handleRectTransformEnd = (index, e) => {
    const node = e.target;
    const { x, y } = node.position();
    const width = node.width() * node.scaleX();
    const height = node.height() * node.scaleY();

    node.scaleX(1);
    node.scaleY(1);

    const updated = [...annotations];
    updated[index] = { ...updated[index], x, y, width, height };
    onAnnotationsChange(updated);
  };

  // --------------------------------------
  // Editable Polygon subcomponent
  // --------------------------------------
  function EditablePolygon({ ann, index, color, sc }) {
    const groupRef = useRef(null);

    // Move entire polygon => shift points
    const handleGroupDragEnd = (e) => {
      const { x, y } = e.target.position();
      const newPoints = ann.points.map((pt) => ({
        x: pt.x + x,
        y: pt.y + y
      }));
      const updated = [...annotations];
      updated[index] = { ...ann, points: newPoints };
      onAnnotationsChange(updated);

      e.target.position({ x: 0, y: 0 });
    };

    const handleVertexDragMove = (ptIdx, e2) => {
      const { x, y } = e2.target.position();
      const newPoints = [...ann.points];
      newPoints[ptIdx] = { x, y };
      const updated = [...annotations];
      updated[index] = { ...ann, points: newPoints };
      onAnnotationsChange(updated);
    };

    const handleClick = (evt) => {
      evt.cancelBubble = true;
      setSelectedShapeIndex(null); // not using Transformer for polygons
    };

    return (
      <Group
        ref={groupRef}
        draggable
        onDragEnd={handleGroupDragEnd}
        onClick={handleClick}
      >
        <Line
          points={flattenPoints(ann.points)}
          fill={color + '55'}
          stroke={color}
          strokeWidth={2 / sc}
          closed
        />
        {ann.points.map((pt, i) => (
          <Circle
            key={i}
            x={pt.x}
            y={pt.y}
            radius={6 / sc}
            fill="#ffffff"
            stroke={color}
            strokeWidth={2 / sc}
            draggable
            onDragMove={(evt) => handleVertexDragMove(i, evt)}
            onClick={(evt) => evt.cancelBubble = true}
          />
        ))}
      </Group>
    );
  }

  const fillColor = activeLabelColor + '55'; // e.g. #FF000055

  return (
    <div className="canvas-container" ref={containerRef}>
      <Stage
        ref={stageRef}
        width={dims.width}
        height={dims.height}
        scaleX={scale}
        scaleY={scale}
        style={{ background: '#dfe6e9' }}
        onWheel={handleWheel}
        onMouseDown={handleMouseDown}
        onMouseMove={handleMouseMove}
        onMouseUp={handleMouseUp}
        onDblClick={handleDblClick}
      >
        <Layer>
          {/* Group => the entire image + shapes so we can pan if tool="move" */}
          <Group
            id="anno-group"
            draggable={selectedTool === 'move'}
            x={imagePos.x}
            y={imagePos.y}
            onDragEnd={(e) => {
              setImagePos({ x: e.target.x(), y: e.target.y() });
            }}
          >
            {konvaImg && (
              <KonvaImage
                image={konvaImg}
                width={konvaImg.width}
                height={konvaImg.height}
              />
            )}

            {/* Finalized annotations */}
            {annotations.map((ann, i) => {
              if (ann.type === 'bbox') {
                return (
                  <Rect
                    key={i}
                    ref={(node) => {
                      rectRefs.current[i] = node;
                    }}
                    x={ann.x}
                    y={ann.y}
                    width={ann.width}
                    height={ann.height}
                    fill={fillColor}
                    stroke={activeLabelColor}
                    strokeWidth={2 / scale}
                    draggable
                    onClick={(evt) => {
                      evt.cancelBubble = true;
                      setSelectedShapeIndex(i);
                    }}
                    onDragEnd={(evt) => handleRectDragEnd(i, evt)}
                    onTransformEnd={(evt) => handleRectTransformEnd(i, evt)}
                  />
                );
              } else if (ann.type === 'polygon') {
                return (
                  <EditablePolygon
                    key={i}
                    index={i}
                    ann={ann}
                    color={activeLabelColor}
                    sc={scale}
                  />
                );
              }
              return null;
            })}

            {/* In-progress bounding box (finalized on mouse up) */}
            {newBox && selectedTool === 'bbox' && (
              <Rect
                x={newBox.x}
                y={newBox.y}
                width={newBox.width}
                height={newBox.height}
                fill={fillColor}
                stroke={activeLabelColor}
                strokeWidth={2 / scale}
              />
            )}

            {/* In-progress polygon (finalized on double-click) */}
            {drawingPolygon &&
              selectedTool === 'polygon' &&
              tempPoints.length > 1 && (
                <Line
                  points={flattenPoints([...tempPoints, tempPoints[0]])}
                  fill={fillColor}
                  stroke={activeLabelColor}
                  strokeWidth={2 / scale}
                  closed
                />
              )}
          </Group>

          {/* Transformer for bounding boxes */}
          <Transformer
            ref={transformerRef}
            rotateEnabled={false}
            anchorCornerRadius={50}
            borderStroke="#00BCD4"
            anchorStroke="#00BCD4"
            anchorFill="#00BCD4"
            enabledAnchors={[
              'top-left',
              'top-center',
              'top-right',
              'middle-right',
              'bottom-right',
              'bottom-center',
              'bottom-left',
              'middle-left',
            ]}
          />
        </Layer>
      </Stage>
    </div>
  );
}
